package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private URL mockUrl;
    private InputStream mockInputStream;

    @BeforeEach
    void setUp() throws IOException {
        mockUrl = mock(URL.class);
        mockInputStream = mock(InputStream.class);
        when(mockUrl.openStream()).thenReturn(mockInputStream);
    }

    @Test
    void parse_withValidArguments_shouldReturnCSVParserInstance() throws IOException {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            // Assertions.notNull should be called for url, charset and format
            mockedAssertions.when(() -> Assertions.notNull(any(), anyString())).then(invocation -> null);

            CSVParser parser = CSVParser.parse(mockUrl, charset, format);

            assertNotNull(parser);
            // The parser should have the correct format assigned
            assertEquals(format, parser.format);
            // The parser should use an InputStreamReader wrapping the InputStream from URL with charset
            // We cannot access the reader directly, but no exception means success
        }
    }

    @Test
    void parse_withNullUrl_shouldThrowException() {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(null, "url")).thenThrow(new NullPointerException("url"));

            NullPointerException exception = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(null, charset, format);
            });
            assertEquals("url", exception.getMessage());
        }
    }

    @Test
    void parse_withNullCharset_shouldThrowException() {
        Charset charset = null;
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(any(), eq("url"))).thenReturn(null);
            mockedAssertions.when(() -> Assertions.notNull(charset, "charset")).thenThrow(new NullPointerException("charset"));

            NullPointerException exception = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(mockUrl, charset, format);
            });
            assertEquals("charset", exception.getMessage());
        }
    }

    @Test
    void parse_withNullFormat_shouldThrowException() {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = null;

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(any(), eq("url"))).thenReturn(null);
            mockedAssertions.when(() -> Assertions.notNull(any(), eq("charset"))).thenReturn(null);
            mockedAssertions.when(() -> Assertions.notNull(format, "format")).thenThrow(new NullPointerException("format"));

            NullPointerException exception = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(mockUrl, charset, format);
            });
            assertEquals("format", exception.getMessage());
        }
    }
}
